  else:
    x = jnp.linspace(jnp.min(jnp.concatenate([p, q])), jnp.max(jnp.concatenate([p, q])), num=100)
    p_dist = _estimate_pdf(p, x)
    q_dist = _estimate_pdf(q, x)

  p_cdf = jnp.cumsum(p_dist)
  q_cdf = jnp.cumsum(q_dist)

  if method == "KS":
    return jnp.max(jnp.abs(p_cdf - q_cdf))
  elif method == "Hellinger":
    return jnp.sqrt(jnp.sum((jnp.sqrt(p_dist) - jnp.sqrt(q_dist)) ** 2)) / jnp.sqrt(2)
  elif method == "JS":
    m = (p_dist + q_dist) / 2
    return jnp.sqrt(
        0.5 * jnp.sum(jnp.where(p_dist > 0, p_dist * jnp.log(p_dist / m), 0)) +
        0.5 * jnp.sum(jnp.where(q_dist > 0, q_dist * jnp.log(q_dist / m), 0)))
  elif method == "min":
    return 1 - jnp.sum(jnp.minimum(p_dist, q_dist))

